unitsize(1 cm);

draw(shift((2,-3))*xscale(2)*yscale(3)*Circle((0,0),1));
draw((-1,0)--(4,0));
draw((0,1)--(0,-6));
draw((2,0)--(2,-6));
draw((0,-3)--(4,-3));

dot("$(2,0)$", (2,0), N);
dot("$(2,-6)$", (2,-6), S);
dot("$(2,-3)$", (2,-3), SE);
